    "python_code": "def reachable(graph, start):
    seen = []

    def dfs(node):
        if node in seen:
            return
        seen.append(node)
        for nxt in graph.get(node, []):
            dfs(nxt)

    dfs(start)
    return seen

graph = {
    "A": ["B", "C"],
    "B": ["D"],
    "C": [],
    "D": []
}
